function parseJsonFromCodeBlock(input) {
  if (!input || typeof input !== "string") return null;

  let text = input.trim();

  // Strip markdown code blocks: ```json ... ``` or ``` ... ```
  // Handles 2 or 3 backticks and optional "json" language tag
  const codeBlockMatch = text.match(/^`{2,3}(?:json)?\s*\n?([\s\S]*?)\n?`{2,3}\s*$/);
  if (codeBlockMatch) {
    text = codeBlockMatch[1].trim();
  }

  try {
    return JSON.parse(text);
  } catch {
    return null;
  }
}

const raw = $json.output[0].content[0].text

return { json: parseJsonFromCodeBlock(raw) }

// This code merges the current loop's data with any enrichment data
// It uses .item to ensure we get the correct data regardless of the index

const currentJob = $('Loop Over Jobs').all()[0].json;
const apolloData = $input.all()[0].json.organization || {};

return {
  json: {
    // 1. Data from the original Job record (The Loop)
    id: currentJob.id,
    job_title: currentJob.job_title,
    company_name: currentJob.company_name,
    location: currentJob.location,
    is_remote: currentJob.is_remote,
    pay_min: currentJob.pay_min,
    pay_max: currentJob.pay_max,
    pay_type: currentJob.pay_type,
    schedules: currentJob.schedules,
    employment_types: currentJob.employment_types,
    description: currentJob.description,
    apply_link: currentJob.apply_link,
    posted_date: currentJob.posted_date,

    // 2. Data from the Domain Search (The IF branch)
    // We use ?. to prevent "Cannot read property" errors
    company_domain: currentJob.website_url,

    // 3. Data from Apollo (The Enrichment branch)
    employee_count: apolloData.estimated_num_employees || 0,
    sic_code: apolloData.sic_codes ? apolloData.sic_codes[0] : null,
    naics_code: apolloData.naics_codes ? apolloData.naics_codes[0] : null,
    industry: apolloData.industry || 'Unknown',
    company_description: apolloData.short_description || ''
  }
};
